// C0684 · CRUD JSON (Nitro)
// server/api/items.ts
let items:any[] = [];
let seq = 1;

export default defineEventHandler(async (event) => {
  if (event.method === "GET") return items;
  if (event.method === "POST") {
    const body = await readBody(event);
    const it = { id: seq++, name: String(body?.name||"") };
    items.push(it);
    return it;
  }
});

